function PriceWatcher() {
  const [items, setItems] = React.useState([
    { name: 'Sony WH-1000XM5', current: 298, target: 250, url: '' },
    { name: 'Kindle Paperwhite', current: 139, target: 99, url: '' }
  ]);
  const [name, setName] = React.useState('');
  const [current, setCurrent] = React.useState('');
  const [target, setTarget] = React.useState('');

  function addItem() {
    if (!name.trim() || !current || !target) return;
    setItems([...items, { name, current: parseFloat(current), target: parseFloat(target), url: '' }]);
    setName('');
    setCurrent('');
    setTarget('');
  }

  function removeItem(idx) {
    setItems(items.filter((_, i) => i !== idx));
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h2 style={{ margin: '0 0 12px 0', fontSize: 18, color: '#1a1a1a' }}>Price Watcher</h2>
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        <input placeholder="Product" value={name} onChange={e => setName(e.target.value)} style={{ flex: 1, padding: '6px 10px', borderRadius: 6, border: '1px solid #ddd', fontSize: 13 }} />
        <input placeholder="Current" type="number" value={current} onChange={e => setCurrent(e.target.value)} style={{ width: 70, padding: '6px 10px', borderRadius: 6, border: '1px solid #ddd', fontSize: 13 }} />
        <input placeholder="Target" type="number" value={target} onChange={e => setTarget(e.target.value)} style={{ width: 70, padding: '6px 10px', borderRadius: 6, border: '1px solid #ddd', fontSize: 13 }} />
        <button onClick={addItem} style={{ padding: '6px 14px', borderRadius: 6, border: 'none', background: '#2563eb', color: '#fff', fontSize: 13, cursor: 'pointer' }}>Add</button>
      </div>
      <div style={{ flex: 1, overflowY: 'auto' }}>
        {items.map((item, i) => {
          const diff = item.current - item.target;
          const alert = diff <= 0;
          return (
            <div key={i} style={{ marginBottom: 12, padding: 12, borderRadius: 8, background: alert ? '#f0fdf4' : '#f8f9fa', border: '1px solid ' + (alert ? '#bbf7d0' : '#e5e7eb') }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div style={{ fontWeight: 600, fontSize: 14, color: '#1a1a1a' }}>{item.name}</div>
                <button onClick={() => removeItem(i)} style={{ background: 'transparent', border: 'none', color: '#999', cursor: 'pointer', fontSize: 16 }}>x</button>
              </div>
              <div style={{ marginTop: 8, display: 'flex', alignItems: 'center', gap: 16 }}>
                <div>
                  <div style={{ fontSize: 11, color: '#888' }}>Current</div>
                  <div style={{ fontSize: 16, fontWeight: 700, color: '#1a1a1a' }}>${item.current}</div>
                </div>
                <div style={{ color: '#ccc' }}>|</div>
                <div>
                  <div style={{ fontSize: 11, color: '#888' }}>Target</div>
                  <div style={{ fontSize: 16, fontWeight: 700, color: alert ? '#16a34a' : '#dc2626' }}>${item.target}</div>
                </div>
                <div style={{ flex: 1, textAlign: 'right' }}>
                  {alert ? (
                    <span style={{ padding: '4px 10px', borderRadius: 20, background: '#22c55e', color: '#fff', fontSize: 11, fontWeight: 600 }}>ALERT: Target reached!</span>
                  ) : (
                    <span style={{ padding: '4px 10px', borderRadius: 20, background: '#e5e7eb', color: '#666', fontSize: 11 }}>${diff} above target</span>
                  )}
                </div>
              </div>
            </div>
          );
        })}
        {items.length === 0 && <div style={{ textAlign: 'center', color: '#999', fontSize: 13, padding: 20 }}>No items tracked yet.</div>}
      </div>
    </div>
  );
}
render(<PriceWatcher/>);
